package com.mdweb.tunnumerique.tools.mdwebNetworkingLib.cache;import android.content.Context;import com.android.volley.toolbox.ImageLoader;import com.mdweb.tunnumerique.tools.mdwebNetworkingLib.Volley;public enum ImageCacheManager {	INSTANCE;	private BitmapMemoryCache mBitmapMemoryCache;	private ImageLoader mImageLoader;	public void initImageCache(Context context) {		mBitmapMemoryCache = new BitmapMemoryCache(getCacheSize());			mImageLoader = new ImageLoader(Volley.getInstance(context).getRequestQueueImage(), mBitmapMemoryCache);	}	public ImageLoader getImageLoader() {		return mImageLoader;	}	private int getCacheSize() {		final int maxMemory = (int) (Runtime.getRuntime().maxMemory() / 1024);		final int cacheSize = maxMemory / 8;		return cacheSize;	}}